class S3Uploader {
  static Future<String> uploadFile({
    required Uint8List bytes,
    required String key,
    required String contentType,
  }) async {
    final uri = Uri.parse('https://${AwsConfig.bucketName}.s3.${AwsConfig.region}.amazonaws.com/$key');
    final amzDate = _amzDateTime(DateTime.now().toUtc());
    final dateStamp = amzDate.substring(0, 8);
    final payloadHash = sha256.convert(bytes).toString();

    final canonicalHeaders =
        'host:${AwsConfig.bucketName}.s3.${AwsConfig.region}.amazonaws.com\n'
        'x-amz-content-sha256:$payloadHash\n'
        'x-amz-date:$amzDate\n';

    final signedHeaders = 'host;x-amz-content-sha256;x-amz-date';

    final canonicalRequest =
        'PUT\n'
        '/${_uriEncodePath(key)}\n'
        '\n'
        '$canonicalHeaders\n'
        '$signedHeaders\n'
        '$payloadHash';

    final algorithm = 'AWS4-HMAC-SHA256';
    final credentialScope = '$dateStamp/${AwsConfig.region}/s3/aws4_request';
    final stringToSign =
        '$algorithm\n'
        '$amzDate\n'
        '$credentialScope\n'
        '${sha256.convert(utf8.encode(canonicalRequest)).toString()}';

    final signingKey = _getSignatureKey(
      AwsConfig.secretAccessKey,
      dateStamp,
      AwsConfig.region,
      's3',
    );

    final signature = _hmacHex(signingKey, stringToSign);

    final authorizationHeader =
        '$algorithm Credential=${AwsConfig.accessKeyId}/$credentialScope, SignedHeaders=$signedHeaders, Signature=$signature';

    final response = await http.put(
      uri,
      headers: {
        'Content-Type': contentType,
        'x-amz-content-sha256': payloadHash,
        'x-amz-date': amzDate,
        'Authorization': authorizationHeader,
      },
      body: bytes,
    );

    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw Exception('S3 upload failed (${response.statusCode}): ${response.body}');
    }

    return uri.toString();
  }

  static String _amzDateTime(DateTime dt) {
    String two(int n) => n.toString().padLeft(2, '0');
    return '${dt.year}${two(dt.month)}${two(dt.day)}T${two(dt.hour)}${two(dt.minute)}${two(dt.second)}Z';
  }

  static String _uriEncodePath(String path) {
    return Uri.encodeComponent(path).replaceAll('%2F', '/').replaceAll('+', '%20');
  }

  static Uint8List _getSignatureKey(String key, String dateStamp, String regionName, String serviceName) {
    final kDate = _hmac(utf8.encode('AWS4$key'), dateStamp);
    final kRegion = _hmac(kDate, regionName);
    final kService = _hmac(kRegion, serviceName);
    return _hmac(kService, 'aws4_request');
  }

  static Uint8List _hmac(List<int> key, String data) {
    final hmac = Hmac(sha256, key);
    return Uint8List.fromList(hmac.convert(utf8.encode(data)).bytes);
  }

  static String _hmacHex(List<int> key, String data) {
    final hmac = Hmac(sha256, key);
    return hmac.convert(utf8.encode(data)).toString();
  }
}

class GoogleVisionService {
  static Future<Map<String, dynamic>> analyzeImage(Uint8List bytes) async {
    final base64Image = base64Encode(bytes);

    final uri = Uri.parse('https://vision.googleapis.com/v1/images:annotate?key=${GoogleVisionConfig.apiKey}');
    final body = {
      'requests': [
        {
          'image': {'content': base64Image},
          'features': [
            {'type': 'LABEL_DETECTION', 'maxResults': 10},
            {'type': 'TEXT_DETECTION', 'maxResults': 10},
            {'type': 'SAFE_SEARCH_DETECTION', 'maxResults': 1},
          ],
        }
      ]
    };

    final response = await http.post(
      uri,
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode(body),
    );

    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw Exception('Vision API failed (${response.statusCode}): ${response.body}');
    }

    return jsonDecode(response.body) as Map<String, dynamic>;
  }
}